oxy_webhelp_navlinks = {"rbs_azure_local_wdac_enabled-d30753e25394":{"topics":[{"title":"Installing RBS on Azure Local with WDAC enabled","shortdesc":"<p class=\"shortdesc\">The Rubrik Backup Service package includes a supplemental policy for installing RBS         on Azure Local where Windows Defender Application Control is enabled. Install Rubrik Backup         Service on an Azure Local system by deploying and activating the supplemental policy and         then installing the Rubrik Backup Service MSI package.<\/p>","href":"saas\/hyper_v\/installing_rbs_wdac_azr_local.html","attributes":{"data-id":"installing_rbs_wdac_azr_local"},"menu":{"hasChildren":false},"tocID":"installing_rbs_wdac_azr_local-d30753e25405","topics":[]}]}};